const data = $input.first().json.body || $input.first().json;

if (!data.plain_text || !data.plain_text.trim()) {
  throw new Error('Missing required field: plain_text');
}
if (!data.job_id) {
  throw new Error('Missing required field: job_id');
}
if (!data.gcs_path) {
  throw new Error('Missing required field: gcs_path');
}

const text = data.plain_text.replace(/\n{3,}/g, '\n\n').trim();
const wordCount = text.split(/\s+/).length;

if (wordCount < 50) {
  return [{ json: { skip: true, reason: `Content too short (${wordCount} words)` } }];
}

return [{
  json: {
    skip: false,
    jobId: data.job_id,
    gcsPath: data.gcs_path,
    chapterTitle: data.chapter_title || '',
    articleText: text,
    wordCount
  }
}];

let script = $input.first().json.choices?.[0]?.message?.content || '';

if (!script) {
  throw new Error('LLM returned empty narration');
}

script = script.replace(/<think>[\s\S]*?<\/think>/gi, '');

const metaPatterns = [
  /^(okay|alright|sure|certainly|of course)[,.].*$/im,
  /^(the user wants|the user is asking|i need to|i should|i will|i'll|let me|let's|first,? i|now,? i).*$/im,
  /^(converting|rewriting|transforming|here is|here's|below is|the following|this is).*?(narration|script|podcast|article|text).*$/im,
  /^(key (rules|points|things)|important:|note:|rule \d)/im,
  /^(I have (converted|rewritten|created)|This is (a|the) (narration|script)).*$/im,
  /^Here is the (narration|script|podcast version).*$/im
];

const lines = script.split('\n');
const cleanLines = lines.filter(line => {
  const trimmed = line.trim();
  if (!trimmed) return true;
  return !metaPatterns.some(pattern => pattern.test(trimmed));
});

script = cleanLines.join('\n').replace(/[#*_~>]/g, '').trim();

if (!script) {
  throw new Error('Narration text is empty after cleanup');
}

const meta = $('Validate & Extract Input').first().json;

return [{
  json: {
    jobId: meta.jobId,
    gcsPath: meta.gcsPath,
    narrationText: script,
    wordCount: script.split(/\s+/).length
  }
}];

const result = $input.first().json;
const meta = $('Validate & Extract Input').first().json;
console.log(`TTS job submitted: ${meta.jobId} → gs://YOUR_BUCKET/${meta.gcsPath}`);
if (result.error || result.detail) {
  throw new Error('TTS service rejected job: ' + (result.error || result.detail));
}
return [{ json: { success: true, jobId: meta.jobId, gcsPath: meta.gcsPath, ...result } }];
